head.b:skin:
* { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: 'Inter', sans-serif;
  background: #060d1a;
  color: #fff;
  min-height: 100vh;
  overflow-x: hidden;
}

/* FONDO ESTADIO */
.bg-stadium {
  position: fixed; inset: 0;
  background:
    linear-gradient(rgb(6,13,26) 0%, rgb(6,13,26) 8%,
    rgba(6,13,26,0.5) 35%, rgba(6,13,26,0.5) 65%,
    rgb(6,13,26) 92%, rgb(6,13,26) 100%),
    url('https://nextjs.fanatiz.com/fanatiz/strapi/production/estadio_OTT_9bf35dcea2.jpg')
    center center / cover no-repeat;
  z-index: 0;
}

/* LAYOUT */
.page-wrap {
  position: relative; z-index: 2;
  min-height: 100vh;
  display: flex; flex-direction: column;
  align-items: center;
}

/* BANNER TOP */
.ad-top {
  width: 100%; display: flex;
  justify-content: center; padding: 12px 16px;
  background: rgba(4,8,18,0.7);
  border-bottom: 1px solid rgba(255,255,255,0.05);
}

/* LAYOUT CON LATERALES */
.main-wrap {
  flex: 1; display: flex;
  width: 100%; max-width: 1400px;
  margin: 0 auto; gap: 20px;
  padding: 20px 16px; align-items: flex-start;
  justify-content: center;
}
.ad-lateral {
  width: 160px; flex-shrink: 0;
  position: sticky; top: 20px;
}
@media (max-width: 1060px) { .ad-lateral { display: none !important; } }

/* CONTENIDO CENTRAL */
.center-col {
  flex: 1; display: flex;
  flex-direction: column;
  align-items: center; justify-content: center;
  width: 100%; max-width: 600px; gap: 20px;
}

/* BANNER 300x250 dentro de card */
.ad-mid {
  display: flex; justify-content: center;
  margin-bottom: 16px;
}

/* CARD PRINCIPAL */
.redirect-card {
  width: 100%; background: rgba(8,16,36,0.92);
  border: 1px solid rgba(255,255,255,0.09);
  border-radius: 18px; overflow: hidden;
  box-shadow: 0 30px 70px rgba(0,0,0,0.65);
}

/* HEADER CARD */
.card-header {
  background: linear-gradient(135deg, #0d2860 0%, #1746b8 60%, #1a3a9a 100%);
  padding: 20px; text-align: center;
  position: relative; overflow: hidden;
}
.card-header::before {
  content: ''; position: absolute;
  top: -50px; left: -50px; right: -50px; height: 130px;
  background: radial-gradient(ellipse at 50% 0%, rgba(255,255,255,0.1), transparent 65%);
}
.card-header .site-name {
  font-family: 'Barlow Condensed', sans-serif;
  font-size: 11px; font-weight: 700;
  letter-spacing: 3px; text-transform: uppercase;
  color: rgba(255,255,255,0.5); margin-bottom: 6px;
}
.card-header h1 {
  font-family: 'Barlow Condensed', sans-serif;
  font-size: 22px; font-weight: 900;
  letter-spacing: 1px; text-transform: uppercase;
  color: #fff; line-height: 1.2;
}

/* BODY CARD */
.card-body { padding: 24px 20px; }

/* DESTINO */
.destination-box {
  background: rgba(2,8,16,0.6);
  border: 1px solid rgba(255,255,255,0.07);
  border-radius: 10px; padding: 12px 16px;
  margin-bottom: 20px;
  display: flex; align-items: center; gap: 10px;
}
.destination-box i { color: #60a5fa; font-size: 14px; flex-shrink: 0; }
.destination-url {
  font-size: 11px; color: #64748b;
  white-space: nowrap; overflow: hidden;
  text-overflow: ellipsis; flex: 1;
  filter: blur(4px);
  user-select: none;
  pointer-events: none;
}

/* CONTADOR */
.counter-wrap {
  display: flex; flex-direction: column;
  align-items: center; gap: 12px;
  margin-bottom: 24px;
}
.counter-label {
  font-size: 11px; font-weight: 600;
  letter-spacing: 2px; text-transform: uppercase;
  color: #475569;
}
.counter-ring {
  position: relative; width: 90px; height: 90px;
}
.counter-ring svg {
  width: 90px; height: 90px;
  transform: rotate(-90deg);
}
.counter-ring .ring-bg {
  fill: none; stroke: rgba(255,255,255,0.06);
  stroke-width: 4;
}
.counter-ring .ring-progress {
  fill: none; stroke: #dc2626;
  stroke-width: 4; stroke-linecap: round;
  stroke-dasharray: 226;
  stroke-dashoffset: 0;
  transition: stroke-dashoffset 1s linear, stroke 0.3s;
}
.counter-ring .ring-progress.finishing {
  stroke: #2563eb;
}
.counter-number {
  position: absolute; inset: 0;
  display: flex; align-items: center; justify-content: center;
  font-family: 'Barlow Condensed', sans-serif;
  font-size: 32px; font-weight: 900; color: #fff;
}
.counter-sub {
  font-size: 11px; color: #475569; text-align: center;
}

/* BARRA DE PROGRESO */
.progress-bar-wrap {
  width: 100%; background: rgba(255,255,255,0.05);
  border-radius: 4px; height: 4px;
  margin-bottom: 20px; overflow: hidden;
}
.progress-bar {
  height: 100%; width: 100%;
  background: linear-gradient(90deg, #dc2626, #2563eb);
  border-radius: 4px;
  transform-origin: left;
  transform: scaleX(1);
  transition: transform 1s linear;
}

/* BOTÓN CONTINUAR */
.btn-continue {
  display: flex; align-items: center; justify-content: center;
  gap: 10px; width: 100%;
  background: linear-gradient(135deg, #2563eb, #1a3ab8);
  color: #fff; text-decoration: none;
  padding: 16px 20px; border-radius: 11px;
  font-family: 'Barlow Condensed', sans-serif;
  font-size: 1.2rem; font-weight: 800;
  letter-spacing: 1.5px; text-transform: uppercase;
  position: relative; overflow: hidden;
  box-shadow: 0 6px 22px rgba(37,99,235,0.45);
  cursor: not-allowed;
  filter: brightness(0.5) saturate(0.3);
  transition: filter 0.4s, box-shadow 0.4s, cursor 0.1s;
  pointer-events: none;
  border: none;
}
.btn-continue.active {
  filter: none;
  cursor: pointer;
  pointer-events: all;
  animation: pulse-btn 2.5s ease-in-out infinite;
}
.btn-continue::after {
  content: ''; position: absolute;
  top: -60%; left: -120%; width: 55%; height: 220%;
  background: rgba(255,255,255,0.14);
  transform: rotate(25deg);
}
.btn-continue.active::after {
  animation: shine 3.5s ease-in-out infinite;
}
@keyframes shine { 0%{left:-120%} 25%{left:130%} 100%{left:130%} }
@keyframes pulse-btn {
  0%,100%{box-shadow:0 6px 22px rgba(37,99,235,0.45)}
  50%{box-shadow:0 8px 30px rgba(37,99,235,0.65)}
}
.btn-continue i { font-size: 18px; flex-shrink: 0; }

/* FOOTER CARD */
.card-footer-note {
  padding: 12px 20px;
  border-top: 1px solid rgba(255,255,255,0.05);
  text-align: center;
  font-size: 11px; color: #334155;
}

/* BANNER BOTTOM */
.ad-bottom {
  width: 100%; display: flex;
  justify-content: center; padding: 12px 16px;
  background: rgba(4,8,18,0.7);
  border-top: 1px solid rgba(255,255,255,0.05);
}

/* OCULTAR ELEMENTOS DE BLOGGER */
.post-footer, .post-author, .post-timestamp,
.post-labels, .blog-feeds, .status-msg-wrap,
h3.post-title, .post-body-default,
#navbar, .blogger-navbar { display: none !important; }

.ad-resp { display: flex; justify-content: center; }
.ad-728 { display: block; }
.ad-320 { display: none; }
@media (max-width: 480px) {
  .ad-728 { display: none; }
  .ad-320 { display: block; }
  .center-col { padding: 20px 12px; }
  .card-header h1 { font-size: 18px; }
}

body.script:
//
(function() {
  var DURACION = 15;
  var circumference = 226;

  function getParam(name) {
    var url = window.location.search;
    var params = new URLSearchParams(url);
    return params.get(name);
  }

  function init() {
    var destUrl  = getParam('url');
    var titulo   = getParam('t') || 'Transmisión en vivo';
    var counter  = document.getElementById('counter');
    var ring     = document.getElementById('ring');
    var bar      = document.getElementById('progress-bar');
    var btn      = document.getElementById('btn-continue');
    var destEl   = document.getElementById('dest-url');
    var titleEl  = document.getElementById('match-title');
    var subEl    = document.getElementById('counter-sub');

    // Sin URL — mostrar error
    if (!destUrl) {
      if (titleEl) titleEl.textContent = 'Enlace no encontrado';
      if (destEl)  destEl.textContent  = 'No se recibió ningún enlace de destino';
      if (counter) counter.textContent = '—';
      return;
    }

    // Mostrar datos
    if (titleEl) titleEl.textContent = decodeURIComponent(titulo);
    if (destEl)  destEl.textContent  = destUrl;
    if (btn)     btn.href            = destUrl;

    // Contador
    var remaining = DURACION;
    var msgs = [
      'Preparando el enlace de transmisión...',
      'Verificando disponibilidad...',
      'Conectando con el servidor...',
      'Listo para reproducir...'
    ];

    // Pausar cuando el usuario no ve la página
    document.addEventListener('visibilitychange', function() {
      if (document.hidden) {
        clearInterval(tick);
      } else {
        tick = setInterval(run, 1000);
      }
    });

    function run() {
      remaining--;
      var pct = remaining / DURACION;

      // Número
      if (counter) counter.textContent = remaining;

      // Ring SVG
      if (ring) {
        ring.style.strokeDashoffset = circumference * (1 - pct);
        if (remaining <= 3) ring.classList.add('finishing');
      }

      // Barra
      if (bar) bar.style.transform = 'scaleX(' + pct + ')';

      // Mensaje
      var msgIdx = Math.floor((1 - pct) * msgs.length);
      if (subEl) subEl.textContent = msgs[Math.min(msgIdx, msgs.length - 1)];

      if (remaining <= 0) {
        clearInterval(tick);
        if (counter) counter.textContent = '✓';
        if (subEl)   subEl.textContent   = '¡Listo! Abriendo transmisión...';
        if (btn) btn.classList.add('active');
        setTimeout(function() { window.location.href = destUrl; }, 500);
      }
    }
    var tick = setInterval(run, 1000);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
//
